# cleanup-runtime.ps1 - Clean up claude-proxy runtime copy files only
# These files are generated by the proxy for Feishu sync. They are NOT Claude Code
# conversation history. Claude Code original data under ~/.claude is NEVER touched.
#
# Dry-run:  powershell -ExecutionPolicy Bypass -File scripts\cleanup-runtime.ps1
# Execute:  powershell -ExecutionPolicy Bypass -File scripts\cleanup-runtime.ps1 -Force

param(
    [switch]$Force
)

$ErrorActionPreference = "Stop"

# --- STRICT BOUNDARY: only these two patterns are allowed ---
$eventsDir = "$env:USERPROFILE\.cc-connect\claude-proxy\events"
$logsDir   = "$env:USERPROFILE\.cc-connect\claude-proxy\logs"

# Hardcoded safelist - NEVER add paths outside .cc-connect\claude-proxy\events|logs
$SAFE_ROOTS = @($eventsDir, $logsDir)

# Verify we are only operating inside the allowed directories
foreach ($dir in $SAFE_ROOTS) {
    $resolved = [System.IO.Path]::GetFullPath($dir)
    if ($resolved -notmatch [regex]::Escape("$env:USERPROFILE\.cc-connect\claude-proxy")) {
        Write-Error "SAFETY CHECK FAILED: resolved path outside allowed boundary: $resolved"
        exit 3
    }
}

# --- Parameters ---
$EVENTS_KEEP   = 20    # Keep last N session files by count
$EVENTS_GRACE  = 24    # Also keep files modified within last N hours
$LOGS_KEEP     = 50    # Keep last N probe files by count

# --- Collect candidates ---
$toDelete = @()

# Events: session-*.jsonl
if (Test-Path $eventsDir) {
    $allEvents = Get-ChildItem "$eventsDir\session-*.jsonl" -File -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending

    $now = Get-Date
    $count = 0
    foreach ($f in $allEvents) {
        $count++
        $hoursOld = ($now - $f.LastWriteTime).TotalHours
        if ($count -le $EVENTS_KEEP -or $hoursOld -le $EVENTS_GRACE) {
            # keep this file
        } else {
            $toDelete += $f
        }
    }
}

# Logs: probe-*.json
if (Test-Path $logsDir) {
    $allLogs = Get-ChildItem "$logsDir\probe-*.json" -File -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending

    $count = 0
    foreach ($f in $allLogs) {
        $count++
        if ($count -gt $LOGS_KEEP) {
            $toDelete += $f
        }
    }
}

# --- Dry-run output ---
if ($toDelete.Count -eq 0) {
    Write-Host "Nothing to clean up."
    exit 0
}

$totalSize = ($toDelete | Measure-Object Length -Sum).Sum
$sizeMB = "{0:F1}" -f ($totalSize / 1MB)

Write-Host "Would delete $($toDelete.Count) file(s) (~$sizeMB MB):"
Write-Host ""

$toDelete | Sort-Object FullName | ForEach-Object {
    $sizeKB = "{0,7:F1}" -f ($_.Length / 1KB)
    $time   = $_.LastWriteTime.ToString("yyyy-MM-dd HH:mm")
    Write-Host "  $sizeKB KB  $time  $($_.Name)"
}

if (-not $Force) {
    Write-Host ""
    Write-Host "This is a DRY-RUN. Use -Force to actually delete."
    Write-Host "These are proxy-generated sync copy files, NOT Claude Code conversation history."
    Write-Host "Claude Code original data under ~/.claude is NEVER touched."
    exit 0
}

# --- Execute deletion ---
Write-Host ""
Write-Host "Deleting..."

$failed = @()
foreach ($f in $toDelete) {
    $resolved = [System.IO.Path]::GetFullPath($f.FullName)
    if ($resolved -notmatch [regex]::Escape("$env:USERPROFILE\.cc-connect\claude-proxy")) {
        Write-Warning "SAFETY REJECT: $($f.FullName)"
        $failed += $f
        continue
    }
    try {
        Remove-Item $f.FullName -Force -ErrorAction Stop
    } catch {
        Write-Warning "Failed to delete $($f.Name): $_"
        $failed += $f
    }
}

$deleted = $toDelete.Count - $failed.Count
Write-Host "Deleted $deleted file(s), freed ~$sizeMB MB."
if ($failed.Count -gt 0) {
    Write-Host "Skipped $($failed.Count) file(s) due to safety checks."
}
